    def _create_config_directories(self):
        """Create configuration directories with secure permissions"""
        home_dir = Path.home()
        config_dir = home_dir / CONFIG_DIR_NAME
        resource_dir = config_dir / RESOURCE_DIR_NAME
        
        # Create directories with restrictive permissions (0o700 = rwx------)
        config_dir.mkdir(mode=0o700, parents=True, exist_ok=True)
