    def _validate_url(self, url):
        """Validate URL against allowlist and ensure HTTPS"""
        from urllib.parse import urlparse
        
        parsed = urlparse(url)
        
        # Enforce HTTPS only
        if parsed.scheme != 'https':
            raise ValueError(f"Only HTTPS URLs are allowed. Rejected: {url}")
        
        # Validate domain against allowlist
        if parsed.netloc not in RESOURCE_CONFIG["allowed_domains"]:
            raise ValueError(f"Domain not in allowlist: {parsed.netloc}")
        
        # Prevent path traversal attempts
        if '..' in parsed.path or parsed.path.startswith('/..'):
            raise ValueError(f"Invalid path detected: {parsed.path}")
        
        return True
    
    def _verify_checksum(self, filepath, expected_sha256):
        """Verify file integrity using SHA256 checksum"""
        sha256_hash = hashlib.sha256()
        
        with open(filepath, "rb") as f:
            for byte_block in iter(lambda: f.read(4096), b""):
                sha256_hash.update(byte_block)
        
        calculated_hash = sha256_hash.hexdigest()
        
        if calculated_hash != expected_sha256:
            raise ValueError(
                f"Checksum mismatch! Expected: {expected_sha256}, Got: {calculated_hash}"
            )
        
        return True
    
